201	// selectInstallState returns load/save functions for the appropriate state file.
202	func selectInstallState(global bool) (
203		load func() (*registry.InstalledState, error),
204		save func(*registry.InstalledState) error,
205	) {
206		if global {
207			return registry.LoadGlobalState, registry.SaveGlobalState
208		}
209		return registry.LoadState, registry.SaveState
210	}
