267	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
268		if len(oldFiles) == 0 {
269			return 0
270		}
271	
272		newSet := make(map[string]bool, len(newFiles))
273		for _, f := range newFiles {
274			newSet[f] = true
275		}
276	
277		removed := 0
278		for _, f := range oldFiles {
279			if newSet[f] {
280				continue
281			}
282			if installPathContainsAny(f, newFiles) {
283				continue
284			}
285			expanded := registry.ExpandHome(f)
286			if err := os.RemoveAll(expanded); err == nil {
287				removed++
288			}
289		}
290		return removed
291	}
292	
293	func installPathContainsAny(parent string, files []string) bool {
294		parent = filepath.ToSlash(strings.TrimSuffix(parent, string(filepath.Separator)))
295		parent = strings.TrimSuffix(parent, "/")
296		if parent == "" {
297			return false
298		}
299		prefix := parent + "/"
300		for _, f := range files {
301			f = filepath.ToSlash(f)
302			if strings.HasPrefix(f, prefix) {
303				return true
304			}
305		}
306		return false
307	}
