309	// commitPluginChanges stages and commits plugin-related changes in the working tree.
310	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
311	func commitPluginChanges(name, version string) {
312		// Stage the project-local plugin tree and the skill copies.
313		paths := []string{ddxroot.JoinRelative("plugins", name) + string(filepath.Separator), ".agents/skills/",
314			".claude/skills/",
315		}
316		ctx := context.Background()
317		for _, p := range paths {
318			if _, err := os.Stat(p); err == nil {
319				gitAdd := internalgit.Command(ctx, "", "add", p)
320				_ = gitAdd.Run()
321			}
322		}
323	
324		// Check if there's anything to commit.
325		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
326		if status.Run() == nil {
327			return // nothing staged
328		}
329	
330		msg := fmt.Sprintf("chore: install %s %s", name, version)
331		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
332		_ = gitCommit.Run()
333	}
