335	func prepareSymlinkTarget(target string, force bool) error {
336		if info, err := os.Lstat(target); err == nil {
337			if info.Mode()&os.ModeSymlink != 0 || force {
338				if err := os.RemoveAll(target); err != nil {
339					return fmt.Errorf("removing existing %s: %w", target, err)
340				}
341				return nil
342			}
343			return fmt.Errorf("%s already exists (use --force to replace)", target)
344		} else if !os.IsNotExist(err) {
345			return fmt.Errorf("checking existing %s: %w", target, err)
346		}
347		return nil
348	}
