766			}
767			for _, source := range sources {
768				pkg.Install.Skills = append(pkg.Install.Skills, registry.InstallMapping{
769					Source: source,
770					Target: ".agents/skills/",
771				})
772			}
773			return pkg, true, nil
774		}
775		return nil, false, nil
776	}
