778	func pluginManifestSkillSources(raw any) ([]string, error) {
779		switch v := raw.(type) {
780		case nil:
781			return nil, nil
782		case string:
783			source := cleanPluginManifestPath(v)
784			if source == "" {
785				return nil, nil
786			}
787			return []string{source}, nil
788		case []any:
789			var sources []string
790			for _, item := range v {
791				text, ok := item.(string)
792				if !ok {
793					return nil, fmt.Errorf("skills entries must be strings")
794				}
795				source := cleanPluginManifestPath(text)
796				if source != "" {
797					sources = append(sources, source)
