861	func filterLocalInstallValidationIssues(root string, issues []registry.ValidationIssue) []registry.ValidationIssue {
862		filtered := issues[:0]
863		roots := localInstallRootAliases(root)
864		ignoreCache := map[string]bool{}
865		for _, issue := range issues {
866			if rel, ok := localInstallIssueRel(roots, issue.Path); ok &&
867				(shouldSkipLocalInstallIssue(rel) || localInstallPathIsGitIgnored(root, rel, ignoreCache)) {
868				continue
869			}
870			filtered = append(filtered, issue)
871		}
872		return filtered
873	}
