875	// localInstallPathIsGitIgnored reports whether rel (a slash path relative to
876	// the local install source root) is gitignored in the source repository.
877	// ddx install --local must not fail validation on broken symlinks that live
878	// under gitignored scratch/tmp paths (e.g. doctor/home/.codex/tmp/...) the
879	// operator never intended to ship. Returns false when the source is not a git
880	// repo or git is unavailable, leaving the well-known-prefix skip list as the
881	// fallback.
882	func localInstallPathIsGitIgnored(root, rel string, cache map[string]bool) bool {
883		rel = strings.TrimSpace(rel)
884		if rel == "" {
885			return false
886		}
887		if cached, ok := cache[rel]; ok {
888			return cached
889		}
890		// git check-ignore exits 0 when the path is ignored, 1 when it is not, and
891		// 128 when the source is not a git repository — treat anything but 0 as
892		// "not ignored" so non-git sources fall through to the prefix skip list.
893		cmd := internalgit.Command(context.Background(), root, "check-ignore", "-q", "--", filepath.FromSlash(rel))
894		ignored := cmd.Run() == nil
895		cache[rel] = ignored
896		return ignored
897	}
