899	func localInstallRootAliases(root string) []string {
900		seen := map[string]bool{}
901		var roots []string
902		add := func(path string) {
903			if strings.TrimSpace(path) == "" {
904				return
905			}
906			abs, err := filepath.Abs(path)
907			if err != nil {
908				abs = path
909			}
910			if !seen[abs] {
911				seen[abs] = true
912				roots = append(roots, abs)
913			}
914			if resolved, err := filepath.EvalSymlinks(abs); err == nil && resolved != "" && !seen[resolved] {
915				seen[resolved] = true
916				roots = append(roots, resolved)
917			}
918		}
