176	// backupUpdateFile copies filePath to backupBase/<path-relative-to-workingDir>.
177	func backupUpdateFile(workingDir, filePath, backupBase string) error {
178		abs := filePath
179		if !filepath.IsAbs(abs) {
180			abs = filepath.Join(workingDir, filePath)
181		}
182		rel, err := filepath.Rel(workingDir, abs)
183		if err != nil {
184			rel = filepath.Base(abs)
185		}
186		dst := filepath.Join(backupBase, rel)
187		if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
188			return err
189		}
190		data, err := os.ReadFile(abs)
191		if err != nil {
192			return err
193		}
194		return os.WriteFile(dst, data, 0o644)
195	}
