197	// performUpdate checks GitHub for the latest version of each installed plugin
198	// and updates any that are outdated (or all if --force). Always refreshes the
199	// embedded `ddx` skill and the AGENTS.md block so projects that ran `ddx init`
200	// under an older DDx version pick up current skill content without re-running
201	// init. Binary updates are intentionally explicit via `ddx upgrade`; `ddx
202	// update` must not replace a locally-built dogfood binary with the latest
203	// public release.
204	func performUpdate(workingDir string, opts *UpdateOptions) (*UpdateResult, error) {
205		// Pre-check: detect dirty update targets before writing anything (atomic
206		// refuse — no file is mutated if any target is dirty without --discard-local).
207		dirtyFiles, _ := collectDirtyUpdateTargets(workingDir)
208		if len(dirtyFiles) > 0 && !opts.DiscardLocal {
209			var sb strings.Builder
210			sb.WriteString("ddx update: uncommitted changes in files that would be overwritten:\n")
211			for _, f := range dirtyFiles {
212				sb.WriteString("  ")
213				if rel, err := filepath.Rel(workingDir, f); err == nil {
214					sb.WriteString(rel)
215				} else {
216					sb.WriteString(f)
217				}
218				sb.WriteString("\n")
219			}
220			sb.WriteString("\nCommit or stash these changes first, or use --force --discard-local to overwrite anyway.")
221			return nil, fmt.Errorf("%s", sb.String())
222		}
223	
224		// Backup dirty files before overwriting when --discard-local is set.
225		var backupPath string
226		if len(dirtyFiles) > 0 && opts.DiscardLocal {
227			backupPath = ddxroot.JoinProject(workingDir, "update-backup",
228				time.Now().UTC().Format("20060102T150405"))
229			for _, f := range dirtyFiles {
230				_ = backupUpdateFile(workingDir, f, backupPath)
231			}
232		}
233	
234		// Refresh the shipped `ddx` skill copy + AGENTS.md block first, regardless
235		// of whether any plugins are installed. This is what lets older projects
236		// pick up new SKILL.md / reference/*.md content without re-init.
237		refreshShippedSkills(workingDir)
238	
239		state, err := registry.LoadState()
240		if err != nil || len(state.Installed) == 0 {
241			return &UpdateResult{Success: true, Message: "Shipped skills refreshed. No packages installed.", BackupPath: backupPath}, nil
242		}
243	
244		reg := registry.BuiltinRegistry()
245	
246		var updated []string
247	
248		for _, entry := range state.Installed {
249			// Filter to specific target if requested.
250			if opts.Resource != "" && entry.Name != opts.Resource {
251				continue
252			}
253	
254			pkg, err := reg.Find(entry.Name)
255			if err != nil {
256				continue // not in registry, skip
257			}
258	
259			// Fetch actual latest version from GitHub.
260			latestVersion := pkg.Version
261			if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
262				latestVersion = strings.TrimPrefix(release.TagName, "v")
263			}
264	
265			if !opts.Force && entry.Version == latestVersion {
266				continue
267			}
268	
269			// Install the latest version.
270			installPkg := *pkg
271			installPkg.Version = latestVersion
272			newEntry, err := registry.InstallPackage(&installPkg, workingDir)
273			if err != nil {
274				return nil, fmt.Errorf("updating %s: %w", entry.Name, err)
275			}
276			state.AddOrUpdate(newEntry)
277			updated = append(updated, entry.Name+" "+entry.Version+" → "+latestVersion)
278		}
279	
280		if err := registry.SaveState(state); err != nil {
281			return nil, fmt.Errorf("saving state: %w", err)
282		}
283	
284		if len(updated) == 0 {
285			return &UpdateResult{Success: true, Message: "Shipped skills refreshed. All packages are up to date.", BackupPath: backupPath}, nil
286		}
287	
288		return &UpdateResult{
289			Success:      true,
290			Message:      "Updated: " + strings.Join(updated, ", "),
291			UpdatedFiles: updated,
292			BackupPath:   backupPath,
293		}, nil
294	}
