// TestInstallGlobal_WritesToGlobalTreeAndAgentLinks verifies bead AC1:
// ddx install <name> --global --silent installs to ${XDG_DATA_HOME}/ddx/global/plugins/<name>/,
// creates a symlink-or-copy under ~/.claude/skills/<name> and ~/.agents/skills/<name>,
// and records the entry in the global state file only (not in the project/home state).
func TestInstallGlobal_WritesToGlobalTreeAndAgentLinks(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	xdgDataHome := t.TempDir()
	t.Setenv("HOME", homeDir)
	t.Setenv("XDG_DATA_HOME", xdgDataHome)

	localPlugin := t.TempDir()
	makeLocalPlugin(t, localPlugin, "myplugin")

	factory := NewCommandFactory(workDir)
	output, err := executeCommand(factory.NewRootCommand(), "install", "myplugin", "--global", "--silent", "--local", localPlugin, "--force")
	require.NoError(t, err, output)

	// Plugin root must land in the global tree.
	globalPluginDir := filepath.Join(xdgDataHome, "ddx", "global", "plugins", "myplugin")
	info, statErr := os.Lstat(globalPluginDir)
	require.NoError(t, statErr, "global plugin dir must exist at %s", globalPluginDir)
	assert.True(t, info.Mode()&os.ModeSymlink != 0 || info.IsDir(), "global plugin dir must be a symlink or dir")

	// Agent-tier skill links must be in the home directory.
	for _, surface := range []string{".agents/skills", ".claude/skills"} {
		skillLink := filepath.Join(homeDir, surface, "myplugin-skill")
		skillInfo, skillErr := os.Lstat(skillLink)
		require.NoError(t, skillErr, "%s must exist for global install", skillLink)
		assert.True(t, skillInfo.Mode()&os.ModeSymlink != 0 || skillInfo.IsDir(),
			"%s must be a symlink or dir for global install", skillLink)
	}

	// Entry must be recorded in global state file only.
	globalState, gsErr := registry.LoadGlobalState()
	require.NoError(t, gsErr)
	assert.NotNil(t, globalState.FindInstalled("myplugin"), "entry must be in global state")

	// Project/home state must NOT have the entry.
	homeState, hsErr := registry.LoadState()
	require.NoError(t, hsErr)
	assert.Nil(t, homeState.FindInstalled("myplugin"), "entry must NOT be in project/home state")

	// Nothing must land in the project directory's skill dirs.
	_, noAgentErr := os.Lstat(filepath.Join(workDir, ".agents", "skills", "myplugin-skill"))
	assert.True(t, os.IsNotExist(noAgentErr), "project .agents/skills must not be created for global install")
	_, noClaudeErr := os.Lstat(filepath.Join(workDir, ".claude", "skills", "myplugin-skill"))
	assert.True(t, os.IsNotExist(noClaudeErr), "project .claude/skills must not be created for global install")
}

// TestPluginListShow_GlobalFlag verifies bead AC3:
// ddx plugin list --global enumerates from the global tier and
// ddx plugin show <name> --global reports from the global tier.
func TestPluginListShow_GlobalFlag(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	xdgDataHome := t.TempDir()
	t.Setenv("HOME", homeDir)
	t.Setenv("XDG_DATA_HOME", xdgDataHome)

	localPlugin := t.TempDir()
	makeLocalPlugin(t, localPlugin, "myplugin")

	factory := NewCommandFactory(workDir)

	// Install globally.
	output, err := executeCommand(factory.NewRootCommand(), "install", "myplugin", "--global", "--silent", "--local", localPlugin, "--force")
	require.NoError(t, err, output)

	// ddx plugin list --global must report the globally installed plugin.
	listOutput, listErr := executeCommand(factory.NewRootCommand(), "plugin", "list", "--global")
	require.NoError(t, listErr, listOutput)
	assert.Contains(t, listOutput, "myplugin", "plugin list --global must show the globally installed plugin")

	// ddx plugin show myplugin --global must report the plugin details.
	showOutput, showErr := executeCommand(factory.NewRootCommand(), "plugin", "show", "myplugin", "--global")
	require.NoError(t, showErr, showOutput)
	assert.Contains(t, showOutput, "myplugin", "plugin show --global must show the plugin name")

	// ddx plugin list (without --global) must NOT show the globally installed plugin.
	localListOutput, _ := executeCommand(factory.NewRootCommand(), "plugin", "list")
	assert.NotContains(t, localListOutput, "myplugin", "plugin list without --global must not show globally installed plugin")
}

